VALUES
  ('heelevel3-53250add-moex-00062', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'essay', '甲 40 年前在自有 A 地興建 B 屋，B 屋已年久失修，漏水嚴重。甲為修
繕 B 屋，乃向乙借款新臺幣（下同）1,000 萬元，並以 B 屋為乙設定抵
押權。後甲將 B屋交由丙包工包料進行重大修繕，約定酬金 1,200 萬元，
然甲迄未支付。試問： 丙得否就 1,200 萬元報酬額，向甲請求對 B 屋
和 A地為其設定抵押權？（13 分） 若甲遲未清償對乙之借款，乙聲請
法院拍賣 B屋，丙之報酬債權與乙之借款債權，孰先受償？（12分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "1004", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00063', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'essay', '甲母和其養女乙串通設局騙婚，由甲偽稱願將獨生女乙嫁與丙為妻，並
約定民國（下同）113 年 2 月14日訂婚，騙使丙於訂婚日致送價值新臺
幣（下同）500 萬元之鑽石項鏈、耳環與手鍊給乙。嗣乙又偽為同意於
同年 5 月 1日結婚，但於結婚當日乙卻不知去向，丙為置辦婚禮支出 100
萬元。112 年 10月丙於初識甲、乙母女之際，乙向丙透露家中有急需，
須辦理貸款。甲、乙隨後即向 A銀行貸款200萬元，約定二人負連帶責
丙知悉其被乙騙婚後，
不甘受損，其得向乙為如何主張？（13 分） 如A銀行同意主債務人甲
和乙延期清償，丙得為如何主張？（12 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "1004", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00064', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '未保留胎兒應繼分之遺產協議分割行為，其效力為何？ 有效  無效  得撤銷  效力未定', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00065', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲將一平板電腦借乙使用，乙使用時，好友丙見到，非常羨慕，表示願以高價購買之，乙見機不 可失，遂以自己名義賣與丙，並將該平板電腦交付於丙。有關乙、丙間之法律行為，下列敘述， 何者正確？ 債權行為與物權行為均無效  債權行為與物權行為均效力未定 債權行為效力未定，物權行為無效  債權行為有效，物權行為效力未定', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00066', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '下列何種請求權，有消滅時效規定之適用？ 分割共有物之請求權  已登記不動產所有人之除去妨害請求權 夫妻間侵權行為而生之損害賠償請求權  夫妻關係而生之同居請求權 33120', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00067', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲有A跑車一部，A車因車禍致車體毀損。甲擅自取乙所有之油漆漆於A車，並向偷車集團購買 丙所有之同類新型引擎一個，安裝於A車。其後甲又將A車讓售於惡意之丁。下列敘述，何者正確？ 甲取得油漆之所有權，乙得依不當得利規定向甲請求償金 甲取得引擎之所有權，丙得依不當得利規定向甲請求償金 甲有權處分A車，丁不僅取得A車之所有權，亦取得油漆及引擎之所有權 乙得以其所有權受侵害為由，對惡意之丁主張侵權行為之損害賠償', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00068', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '下列關於錯誤意思表示之敘述，何者錯誤？ 甲欲與乙畫家締約，使乙畫家為甲畫肖像，但卻將丙畫家認為是乙畫家而與丙畫家締約，甲無 過失時，得撤銷其與丙間之契約 甲欲向丁購買A馬，卻未注意誤以為B馬為A馬而購買之，則甲得撤銷其與丁間之契約 甲內心欲以新臺幣（下同）300萬元出賣C車予戊，於書寫時寫成30萬元，甲無過失時，得撤 銷其與戊間之契約 甲以為前來應徵之庚，係曾在美國留學3年取得學位而與其訂立僱傭契約，甲無過失時，得撤 銷其與庚間之契約', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00069', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '下列關於附停止條件法律行為之敘述，何者錯誤？ 須以將來不確定之事實為法律行為附款 是法律行為之生效要件 條件成就時，縱無特約，皆回溯自約定條件時生效 條件成就前，尚未發生效力', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00070', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲竊取乙於丙銀行存款之存摺、印章及密碼後，於乙察覺遭竊前，甲持乙之印章、存摺及密碼至 丙銀行櫃臺，佯稱自己為乙，盜領乙之存款新臺幣十萬元。丙銀行於下列何種情形，得主張其已 對乙清償上述存款之債務？ 丙須不知甲非債權人而為給付 丙須無重大過失不知甲非債權人而為給付 丙須無具體輕過失不知甲非債權人而為給付 丙須無抽象輕過失不知甲非債權人而為給付', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00071', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '當事人無特約之情形下，下列何者無收取擔保物所生天然孳息之權利？ 典權人    扣押抵押物前之抵押權人 動產質權人    留置權人', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL)
